import React, { useState } from 'react';
import ImportDataSidebar from './ImportDataSidebar';
import './ChatBox.css';
import SideNav from './SideNav';
import { useNavigate } from 'react-router-dom';

function ChatBox({ jiraData, handleFetchData }) {  // Accepting handleFetchData as prop
  const [userStory, setUserStory] = useState('');
  const [storyDetails, setStoryDetails] = useState(null);
  const [messages, setMessages] = useState([]);
  const [isSidebarVisible, setIsSidebarVisible] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const navigate = useNavigate();

  const logout = () => {
    navigate('/Login');
  };

  const generateTestCases = async (userStoryData) => {
    setIsProcessing(true);
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/GenerateTestCases', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ userStory: userStoryData }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate test cases');
      }

      const responseData = await response.json();
      const candidates = responseData.candidates;

      if (candidates && candidates.length > 0) {
        const testCaseContent = candidates[0].content.parts.map(part => part.text).join('\n');
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: `Generated test cases:\n${testCaseContent}`, isUserMessage: false },
        ]);
      } else {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'No test cases found.', isUserMessage: false },
        ]);
      }
    } catch (error) {
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: `Error generating test cases. Error: ${error.message}`, isUserMessage: false },
      ]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSendMessage = () => {
    let messageText = userStory;
    if (storyDetails) {
      messageText = userStory;  // You could consider adjusting this if you'd like to display other fields of the selected story (e.g., summary, reporter, etc.)
    }

    setMessages((prevMessages) => [
      ...prevMessages,
      { text: messageText, isUserMessage: true },
    ]);
    setUserStory('');
    generateTestCases(messageText);
  };

  // Handle selecting user story from sidebar
  const handleSelectUserStory = (story) => {
    console.log("Received story in ChatBox:", story);  // Debug: Log the received story
    setStoryDetails({
      summary: story.summary,
      description: story.description,
      reporter: story.reporter,
    });
    setUserStory(story.description);  // Make sure description is being set correctly here
  };

  // Handle closing sidebar
  const handleCloseSidebar = () => {
    setIsSidebarVisible(false);
  };

  // Handle Import Data Button Click (open sidebar and fetch data)
  const handleImportDataClick = async () => {
    setIsSidebarVisible(true);  // Open sidebar
    await handleFetchData();  // Trigger the fetch data function passed from App.js
  };

  return (
    <div className="chat-container">
      <SideNav logout={logout} />

      <div className="chat-box">
        <div className="chat-box-messages">
          {messages.map((message, index) => (
            <div
              key={index}
              className={`message ${message.isUserMessage ? 'user-message' : 'bot-message'}`}
              dangerouslySetInnerHTML={{ __html: message.text }}
            />
          ))}
        </div>
        <div className="chat-input-container">
          <textarea
            value={userStory}  // This should be updated with the description when a user story is selected
            onChange={(e) => setUserStory(e.target.value)}  // Allow the user to edit the story description
            placeholder="Type your user story or select one from the sidebar."
            rows="6"
            disabled={isProcessing}
          />
          <button 
            onClick={() => {
              handleImportDataClick();  // Trigger sidebar opening and data fetching
              handleSendMessage();  // Send the message (generate test cases)
            }} 
            disabled={isProcessing}
          >
            &#x2191;  {/* This represents the upward arrow (or any other icon) */}
          </button>
        </div>
      </div>

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && (
        <ImportDataSidebar
          jiraData={jiraData}
          onSelectUserStory={handleSelectUserStory}
          onClose={handleCloseSidebar}
          isSidebarVisible={isSidebarVisible}
        />
      )}
    </div>
  );
}

export default ChatBox;
